#include <stdio.h>
#include <math.h>

void calculate_stats(double x[], double y[], int n, 
                    double *cov, double *corr) {
    double sum_x = 0, sum_y = 0;
    double sum_xy = 0, sum_x2 = 0, sum_y2 = 0;

    // Calculate sums
    for (int i = 0; i < n; i++) {
        sum_x += x[i];
        sum_y += y[i];
        sum_xy += x[i] * y[i];
        sum_x2 += x[i] * x[i];
        sum_y2 += y[i] * y[i];
    }

    double mean_x = sum_x / n;
    double mean_y = sum_y / n;

    // Sample covariance
    *cov = (sum_xy - n * mean_x * mean_y) / (n - 1);

    // Standard deviations
    double var_x = (sum_x2 - n * mean_x * mean_x) / (n - 1);
    double var_y = (sum_y2 - n * mean_y * mean_y) / (n - 1);
    double std_x = sqrt(var_x);
    double std_y = sqrt(var_y);

    // Pearson correlation
    *corr = *cov / (std_x * std_y);
}

int main() {
    double x[] = {2, 4, 6, 8, 10};
    double y[] = {1, 3, 5, 7, 9};
    int n = 5;
    double cov, corr;

    calculate_stats(x, y, n, &cov, &corr);

    printf("Covariance: %.2f\n", cov);
    printf("Correlation: %.2f\n", corr);

    return 0;
}

import java.util.Arrays;

public class CorrelationCalculator {

    public static double[] mean(double[][] data) {
        int n = data.length;
        int m = data[0].length;
        double[] means = new double[m];

        for (int j = 0; j < m; j++) {
            double sum = 0;
            for (int i = 0; i < n; i++) {
                sum += data[i][j];
            }
            means[j] = sum / n;
        }
        return means;
    }

    public static double covariance(double[] x, double[] y) {
        int n = x.length;
        double meanX = Arrays.stream(x).average().orElse(0);
        double meanY = Arrays.stream(y).average().orElse(0);

        double sum = 0;
        for (int i = 0; i < n; i++) {
            sum += (x[i] - meanX) * (y[i] - meanY);
        }
        return sum / (n - 1);
    }

    public static double stdDev(double[] x) {
        double mean = Arrays.stream(x).average().orElse(0);
        double variance = Arrays.stream(x)
            .map(val -> (val - mean) * (val - mean))
            .average().orElse(0);
        return Math.sqrt(variance);
    }

    public static double correlation(double[] x, double[] y) {
        double cov = covariance(x, y);
        double stdX = stdDev(x);
        double stdY = stdDev(y);
        return cov / (stdX * stdY);
    }

    public static double[][] correlationMatrix(double[][] data) {
        int numVars = data[0].length;
        double[][] matrix = new double[numVars][numVars];

        for (int i = 0; i < numVars; i++) {
            for (int j = 0; j < numVars; j++) {
                double[] colI = new double[data.length];
                double[] colJ = new double[data.length];
                for (int k = 0; k < data.length; k++) {
                    colI[k] = data[k][i];
                    colJ[k] = data[k][j];
                }
                matrix[i][j] = correlation(colI, colJ);
            }
        }
        return matrix;
    }

    public static void main(String[] args) {
        double[][] data = {
            {10, 25}, {12, 28}, {15, 32}, {18, 35}, {20, 40}
        };

        double corr = correlation(
            Arrays.stream(data).mapToDouble(r -> r[0]).toArray(),
            Arrays.stream(data).mapToDouble(r -> r[1]).toArray()
        );
        System.out.printf("Correlation: %.4f%n", corr);
    }
}
